function return9197(){
    var  n9197 = false;
    if(
        ("ATT" == Services.getValue(RequestFor.dataBinding))||
        ("OTH" == Services.getValue(RequestFor.dataBinding))||
        ("OFQ" == Services.getValue(RequestFor.dataBinding))||
        ((null != Services.getValue(ReturnProcessType.dataBinding))&&
        ("" != Services.getValue(ReturnProcessType.dataBinding)))
    ){
         n9197 = true;
    }
    return n9197;
}

Javascript.validate:
  // Validation: only numeric characters allowed and two decimal places.
  // Error message: Currency amounts must be in the format of 0.00.
  // Max length: 999999.99
  var value = Services.getValue(Fee.dataBinding);     
   
  var maxVal = 999999.99;      
  var err = null;

  if( '0.00 ' != value )
  {   err = validateCurrencyValue(value, maxVal);
    if( null == err)
    { 
      var returnVal = WPU.formatToTwoDP(value);
      Services.setValue(Fee.dataBinding, returnVal);
    } 
  }
  return err;

Javascript.transformToModel:

  if( null == value || "" == value )
  {  return "0.00 ";
  }
  else
  { return value;
  }
